messages.content:
body {
  background-color: #f2f2f2;
  font-family: Arial, sans-serif;
}

h1 {
  color: #333;
  text-align: center;
}

p {
  color: #666;
  text-align: center;
  font-size: 18px;
}

function greetUser() {
  var name = prompt("Please enter your name:");
  if (name != null) {
    alert("Hello, " + name + "! Welcome to my website.");
  }
}

document.addEventListener("DOMContentLoaded", function(event) {
  greetUser();
});

